     * <p><b>Performance:</b> This method performs a full scan of the batch (O(n)) and may trigger
     * decompression for compressed batches. It should not be called in hot paths.
     *
     * @return an {@link java.util.Optional} containing the offset of the record with the maximum
     *         timestamp, or {@link java.util.Optional#empty()} for magic v0 batches or empty batches
     * @see #maxTimestamp()
     * @see #streamingIterator(BufferSupplier)
     */
    default Optional<Long> offsetOfMaxTimestamp() {
        if (magic() == RecordBatch.MAGIC_VALUE_V0) return Optional.empty();
        long maxTimestamp = maxTimestamp();
        try (CloseableIterator<Record> iter = streamingIterator(BufferSupplier.create())) {
            while (iter.hasNext()) {
                Record record = iter.next();
                if (maxTimestamp == record.timestamp()) return Optional.of(record.offset());
            }
        }
        return Optional.empty();
    }
}

