/**
 * Returns an iterator over all {@link Record}s in this batch.
 *
 * <p>For uncompressed batches, records are read directly from the backing buffer with no
 * additional allocation. For compressed batches, the entire record set is eagerly decompressed
 * into a {@link java.util.List} before the iterator is returned. This ensures that the
 * underlying decompression stream is always closed, but it means that the full decompressed
 * payload is held in memory for the lifetime of the iterator.
 *
 * <p>Callers that need lower memory overhead for large compressed batches should use
 * {@link #streamingIterator(org.apache.kafka.common.utils.BufferSupplier)} instead, which
 * decompresses lazily but requires the caller to close the iterator.
 *
 * @return an iterator over the records in this batch; never {@code null}
 * @see #streamingIterator(org.apache.kafka.common.utils.BufferSupplier)
 * @see #skipKeyValueIterator(org.apache.kafka.common.utils.BufferSupplier)
 */
@Override
public Iterator<Record> iterator() {
    if (count() == 0)
        return Collections.emptyIterator();

    if (!isCompressed())
        return uncompressedIterator();

    // for a normal iterator, we cannot ensure that the underlying compression stream is closed,
    // so we decompress the full record set here. Use cases which call for a lower memory footprint
    // can use `streamingIterator` at the cost of additional complexity
    try (CloseableIterator<Record> iterator = compressedIterator(BufferSupplier.NO_CACHING, false)) {
        List<Record> records = new ArrayList<>(count());
        while (iterator.hasNext())
            records.add(iterator.next());
        return records.iterator();
    }
}

