/**
 * Returns a {@link CloseableIterator} over the records in this batch that skips parsing of
 * record keys, values, and headers for compressed batches, reducing allocation and GC pressure
 * in callers (such as the log validator) that only need record offsets and timestamps.
 *
 * <p>For uncompressed batches, skipping key/value/header bytes via
 * {@link java.io.InputStream#skip(long)} is less efficient than simply reading them (because
 * the underlying {@code ByteBufferInputStream} allocates a temporary byte array for skips), so
 * this method falls back to the standard uncompressed iterator in that case.
 *
 * <p>For compressed batches, a streaming decompression iterator is returned that parses only
 * the record metadata fields. The iterator is lazy (decompresses on demand) and must be closed
 * by the caller to release the underlying decompression stream.
 *
 * @param bufferSupplier supplier of scratch {@link java.nio.ByteBuffer}s for decompression;
 *        a reusing supplier reduces allocation pressure
 * @return a {@link CloseableIterator} that yields records with empty key/value/headers for
 *         compressed batches, or full records for uncompressed batches; must be closed by the caller
 * @see #streamingIterator(org.apache.kafka.common.utils.BufferSupplier)
 * @see #iterator()
 */
@Override
public CloseableIterator<Record> skipKeyValueIterator(BufferSupplier bufferSupplier) {
    if (count() == 0) {
        return CloseableIterator.wrap(Collections.emptyIterator());
    }

    /*
     * For uncompressed iterator, it is actually not worth skipping key / value / headers at all since
     * its ByteBufferInputStream's skip() function is less efficient compared with just reading it actually
     * as it will allocate new byte array.
     */
    if (!isCompressed())
        return uncompressedIterator();

    // we define this to be a closable iterator so that caller (i.e. the log validator) needs to close it
    // while we can save memory footprint of not decompressing the full record set ahead of time
    return compressedIterator(bufferSupplier, true);
}

