/**
 * A {@link Records} implementation backed by a ByteBuffer. This is used only for reading or
 * modifying in-place an existing buffer of record batches. To create a new buffer see {@link MemoryRecordsBuilder},
 * or one of the {@link #builder(ByteBuffer, byte, Compression, TimestampType, long)} variants.
 */
public class MemoryRecords extends AbstractRecords {

@Override
public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
    if (((long) position) + length > buffer.limit())
        throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
                + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());

    return Utils.tryWriteTo(channel, position, length, buffer);
}

arguments.new_str:
/**
 * Writes a contiguous slice of this record set's bytes to the given channel, starting at the
 * absolute byte {@code position} within the backing buffer and writing at most {@code length}
 * bytes.
 *
 * <p>This is a non-blocking, best-effort write: the channel may accept fewer bytes than
 * requested in a single call (e.g. when the channel's send buffer is full). The actual number
 * of bytes written is returned so that callers can loop until all bytes are transferred.
 *
 * @param channel  the destination channel; must be open and writable
 * @param position the zero-based byte offset within this record set from which to start writing;
 *                 must be &ge; 0
 * @param length   the maximum number of bytes to write; must be &ge; 0
 * @return the number of bytes actually written to the channel in this call
 * @throws IllegalArgumentException if {@code position + length} exceeds the buffer limit
 * @throws IOException              if an I/O error occurs while writing to the channel
 * @see #writeFullyTo(java.nio.channels.GatheringByteChannel)
 */
@Override
public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
    if (((long) position) + length > buffer.limit())
        throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
                + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());

    return Utils.tryWriteTo(channel, position, length, buffer);
}

