arguments.new_str:
/**
 * Returns a zero-copy view into a sub-range of this record set's backing buffer.
 *
 * <p>The returned {@code MemoryRecords} shares the underlying bytes with this instance; no
 * data is copied. The view starts at the given absolute byte {@code position} within this
 * record set and extends for at most {@code size} bytes. If {@code size} would extend beyond
 * the end of the buffer, the view is silently truncated to the available bytes.
 *
 * <p>For the returned slice to be iterable as a sequence of complete batches, {@code position}
 * should be aligned to a batch boundary; otherwise the first batch in the slice may be
 * unreadable.
 *
 * @param position the zero-based byte offset within this record set at which the slice begins;
 *                 must be &ge; 0 and &le; {@link #sizeInBytes()}
 * @param size     the maximum number of bytes to include in the slice; must be &ge; 0
 * @return a {@code MemoryRecords} view covering bytes [{@code position},
 *         min({@code position + size}, {@link #sizeInBytes()}))
 * @throws IllegalArgumentException if {@code position} is negative, greater than the buffer
 *         limit, or if {@code size} is negative
 * @see #buffer()
 */
@Override
public MemoryRecords slice(int position, int size) {
    if (position < 0)
        throw new IllegalArgumentException("Invalid position: " + position + " in read from " + this);
    if (position > buffer.limit())
        throw new IllegalArgumentException("Slice from position " + position + " exceeds end position of " + this);
    if (size < 0)
        throw new IllegalArgumentException("Invalid size: " + size + " in read from " + this);

